  ('optometrist-moex-00704', 'optometrist', 'optometrist-moex-112-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '一位配戴雙焦眼鏡的老花眼患者有-6.00 D的近視且已完全矯正，其總景深為1.00 D。該患者透過雙焦近 附加子片觀看時，清晰的範圍介於66.67cm到25.00cm。若患者沒有配戴眼鏡時，調節近點為何？', '["11.11cm", "12.50cm", "14.29cm", "16.67cm"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "77d308980065", "answer_pdf_sha1": "815ebca9fd63", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 41, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
